css:
@media print {
    @page{
        size:76mm 50mm;
        margin:0;
    }

    html, body{
        width:76mm;
        height:auto;
        margin:0 !important;
        padding:0 !important;
    }
}

*{
    margin:0;
    padding:0;
    box-sizing:border-box;
    border:none !important;
    outline:none !important;
    box-shadow:none !important;
}

.print-format{
    margin:0 !important;
    padding:0 !important;
}

/* MAIN ROW */
.wrapper{
    width:76mm;
    min-height:50mm;
    height:50mm;
    display:flex;
    flex-wrap:nowrap;

    page-break-inside:avoid !important;
    break-inside:avoid !important;

    page-break-after:auto !important;
    break-after:auto !important;

    margin:0 !important;
    padding:0 !important;
}

/* SINGLE LABEL */
.label{
    width:38mm;
    height:50mm;
    flex:0 0 38mm;
    overflow:hidden;
    padding:1mm;
}

.details-block{
    text-align:left !important;
    font-size:11px;
    line-height:1.5;
    padding-left:1mm;
}

.barcode-container{
    text-align:center;
    margin-top:1mm;
}

.barcode-container img{
    width:36mm;
    height:15mm;
    display:block;
    margin:auto;
}

.bottom-text{
    text-align:center;
    font-size:11px;
}

.secret-code{
    text-align:center;
    font-size:13px;
    letter-spacing:1.5px;
    margin-top:2px;
}

/* IMPORTANT */
.wrapper:last-child{
    page-break-after:auto !important;
}

